1	/**
2	 * The Lattice — notification substrate apparatus.
3	 *
4	 * The Lattice owns the `lattice/pulses` book, exposes a small `LatticeApi`
5	 * for emitters, consumes a new `latticeChannels` kit contribution type
6	 * (channel factories), and fans newly-emitted pulses out via a Phase 2 CDC
7	 * watcher on its own pulses book.
8	 *
9	 * Phase 2 dispatch is deliberate:
10	 *
11	 *   1. Channel I/O is a side effect layered on top of a persistent event
12	 *      record. A `send()` failure (HTTP 5xx, network drop, etc.) must not
13	 *      roll back the underlying pulse write — the pulse is the durable
14	 *      record; dispatch is best-effort.
15	 *   2. The dispatcher patches `deliveryState` on the same book it watches.
16	 *      Phase 1 would re-enter the CDC dispatch and risk recursion; Phase 2
17	 *      runs post-commit, so the delivery-state update fires cleanly on the
18	 *      next cycle (and is ignored by the dispatcher, which only reacts to
19	 *      create events and to update events that move a pulse off `pending`
20	 *      are no-ops — see the handler body).
21	 *
22	 * Pulses are immutable from the public API's perspective. The Lattice itself
23	 * writes `deliveryState` transitions (pending → delivered/failed). `show`,
24	 * `list`, `count`, and `resolveId` round out the read surface.
25	 *
26	 * See: docs/architecture/apparatus/lattice.md
27	 */
28	
29	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
30	import { guild, generateId } from '@shardworks/nexus-core';
31	import type { Book, StacksApi, WhereClause } from '@shardworks/stacks-apparatus';
32	
33	import type {
34	  EmitPulseRequest,
35	  LatticeApi,
36	  LatticeChannel,
37	  LatticeChannelFactory,
38	  LatticeChannelInstanceConfig,
39	  LatticeConfig,
40	  PulseDoc,
41	  PulseFilters,
42	} from './types.ts';
43	
44	import { pulseList, pulseShow } from './tools/index.ts';
45	
46	// ── Kit contribution vocabulary ─────────────────────────────────────
47	
